from itertools import islice
from collections import Counter
def agen(): # generator of terms
    alst, ways = [1], Counter()
    while True:
        yield alst[-1]
        partial = 0
        for i in range(1, 1+len(alst)):
            partial += alst[-i]
            ways[partial] += 1
        alst.append(ways[alst[-1]])
print(list(islice(agen(), 84))) # _Michael S. Branicky_, May 17 2026

